      };

      const { error } = await supabase.from('contacts').update(updates).eq('id', selectedContact.id);

      if (error) {
          console.error("Error updating contact:", error);
          alert(`Failed to update contact: ${error.message}`);
          return;
      }

      const updated: Contact = {
