        doc.setLineWidth(0.5);
        doc.line(140, 53, 195, 53);

        doc.setFontSize(12);
        doc.setFont("helvetica", "bold");
        doc.text('Balance:', 140, 60);
        doc.text(`Rs. ${selectedContact.balance.toLocaleString()}`, 195, 60, { align: 'right' });
        doc.setFont("helvetica", "normal");

        // --- Table ---
        const tableColumn = ["Date", "Description", "Type", "Credit", "Payment"];
        const tableRows = reportTransactions.map(t => {
           return [
              t.date,
              t.description || '',
              t.type,
              t.type === 'CREDIT' ? t.amount.toLocaleString() : '-',
              t.type === 'PAYMENT' ? t.amount.toLocaleString() : '-',
           ];
        });

        autoTable(doc, {
          head: [tableColumn],
          body: tableRows,
          startY: 70,
          theme: 'grid',
          headStyles: { fillColor: [50, 50, 50], textColor: [255, 255, 255] },
          styles: { fontSize: 9, cellPadding: 3 },
          columnStyles: {
              3: { halign: 'right', textColor: [200, 0, 0] }, // Credit Red
              4: { halign: 'right', textColor: [0, 150, 0] }  // Payment Green
          }
        });

        // --- Footer ---
        const pageCount = doc.getNumberOfPages();
        for(let i = 1; i <= pageCount; i++) {
            doc.setPage(i);
            doc.setFontSize(8);
            doc.setTextColor(150);
            doc.text(`Page ${i} of ${pageCount}`, 195, 290, { align: 'right' });
            doc.text('Generated by Smart Credit Ledger', 14, 290);
        }

        doc.save(`Statement_${selectedContact.name.replace(/\s+/g, '_')}.pdf`);
      } catch (err) {
        console.error("PDF generation error:", err);
        alert("Failed to generate PDF. Please ensure all libraries are loaded.");
      }
  };

  const handleStartNewMonth = async () => {
      if (!selectedContact || selectedContact.type !== 'RENT') return;

      if (!window.confirm("Start a new month? This will reset the current savings balance to 0 and advance the dates.")) {
          return;
      }

      setIsLoading(true);

      try {
        // 1. Calculate new dates
        let newStart = new Date();

        if (selectedContact.endDate) {
            // Parse existing end date
            const currentEnd = new Date(selectedContact.endDate);
            // Add 1 day
            newStart = new Date(currentEnd);
            newStart.setDate(newStart.getDate() + 1);
        }

        // New end date = New start + 1 month
        const newEnd = new Date(newStart);
        newEnd.setMonth(newEnd.getMonth() + 1);

        const newStartDateStr = newStart.toISOString().slice(0, 10);
        const newEndDateStr = newEnd.toISOString().slice(0, 10);

        // 2. Create Closing Transaction (if balance > 0)
        const closingBalance = selectedContact.balance;

        if (closingBalance > 0) {
            const txPayload = {
                contact_id: selectedContact.id,
                date: new Date().toISOString().slice(0, 10),
                amount: closingBalance,
                type: 'CREDIT', // Withdraw/Reset
                description: 'Month End Reset',
                balance_after: 0,
                has_attachment: false
            };

            const { error: txError } = await supabase.from('transactions').insert([txPayload]);
            if (txError) throw txError;
        }

        // 3. Update Contact
        const updates = {
            balance: 0,
            start_date: newStartDateStr,
            end_date: newEndDateStr,
            last_updated: new Date().toISOString()
        };

        const { error: contactError } = await supabase
            .from('contacts')
            .update(updates)
            .eq('id', selectedContact.id);

        if (contactError) throw contactError;

        // 4. Refresh Data
        await fetchData();

        // Update local selectedContact to reflect changes immediately
        setSelectedContact({
            ...selectedContact,
            balance: 0,
            startDate: newStartDateStr,
            endDate: newEndDateStr,
            lastUpdated: updates.last_updated
        });

      } catch (err: any) {
          console.error("Error starting new month:", err);
          alert(`Failed to start new month: ${err.message}`);
      } finally {
          setIsLoading(false);
      }
  };

