            </header>

            <div className="p-4">
                {/* Date Filter */}
                <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 mb-4">
                     <div className="flex items-center gap-2 mb-3">
                        <button 
                            onClick={() => setReportFilterType('CUSTOM')}
