  const handleDownloadReport = () => {
      if (!selectedContact) return;
      try {
        const doc = new jsPDF();
        doc.setFontSize(22);
        doc.setTextColor(40, 40, 40); 
        doc.text(shopName || 'Credit Ledger', 14, 20);
        doc.setFontSize(10);
        doc.setTextColor(100, 100, 100);
