                         <div className="flex-1 bg-red-50 border border-red-200 rounded-lg p-3"><p className="text-xs text-slate-600">To Collect</p><p className="text-lg font-bold text-red-700">Rs. {totals.customerToCollect.toLocaleString()}</p></div>
