        <div className="p-4 bg-white mb-2"><div className="bg-gray-50 rounded-lg p-6 flex flex-col items-center justify-center"><h2 className={`text-xl font-bold ${selectedContact.balance > 0 ? 'text-red-600' : 'text-green-600'}`}>Rs. {selectedContact.balance.toLocaleString()}</h2><p className="text-gray-500 text-sm">{isSupplier ? 'To Pay' : 'To Collect'}</p></div></div>
        <div className="flex-1">{currentTransactions.length > 0 ? currentTransactions.map(t => <TransactionRow key={t.id} transaction={t} onClick={handleEditTransaction} />) : <div className="p-8 text-center text-gray-400">No transactions found</div>}</div>
        <div className="fixed bottom-0 left-0 right-0 bg-white px-4 pt-4 pb-10 flex gap-4 border-t border-gray-200 z-40"><button onClick={() => startTransaction('CREDIT')} className="flex-1 bg-red-700 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 active:bg-red-800 transition-colors"><ArrowDown size={18} />Credit</button><button onClick={() => startTransaction('PAYMENT')} className="flex-1 bg-green-700 text-white font-semibold py-3 rounded-lg flex items-center justify-center gap-2 active:bg-green-800 transition-colors"><ArrowUp size={18} />Payment</button></div>
      </div>
    );
  }
  return null;
}

