  const [cashDesc, setCashDesc] = useState('');

  // Transaction Form State
  const [transType, setTransType] = useState<TransactionType>('CREDIT');
  const [transAmount, setTransAmount] = useState('');
  const [transDate, setTransDate] = useState(new Date().toISOString().slice(0, 10));
  const [transDesc, setTransDesc] = useState('');

  const theme = THEMES[appTheme];

  useEffect(() => {
    contactsRef.current = contacts;
  }, [contacts]);

  useEffect(() => {
    if (!window.history.state) {
        window.history.replaceState({ view: 'DASHBOARD', contactId: null, tab: 'SUPPLIER' }, '', window.location.pathname);
    }

    const handlePopState = (event: PopStateEvent) => {
      const state = event.state;
      if (!state) {
        setCurrentView('DASHBOARD');
        setSelectedContact(null);
        return;
      }

      const view = state.view || 'DASHBOARD';
      setCurrentView(view);

      if (state.tab && (view === 'DASHBOARD')) {
          setActiveTab(state.tab);
      }

      if (state.contactId) {
        const contact = contactsRef.current ? contactsRef.current.find(c => c.id === state.contactId) : null;
        if (contact) {
            setSelectedContact(contact);
        } else {
            setSelectedContact(null);
            if (['DETAIL', 'EDIT_CONTACT', 'TRANSACTION_FORM', 'REPORT'].includes(view)) {
                setCurrentView('DASHBOARD');
            }
        }
      } else {
        setSelectedContact(null);
      }
    };

    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const changeTab = (tab: ContactType) => {
      setActiveTab(tab);
      window.history.replaceState({ ...window.history.state, tab: tab }, '', window.location.pathname);
  };

  const navigateTo = (view: string, contactId: string | null = null) => {
    let hash = '';
    if (view !== 'DASHBOARD') {
        hash = `#${view.toLowerCase()}`;
        if (contactId) hash += `/${contactId}`;
    }
    window.history.pushState({ view, contactId }, '', hash || window.location.pathname);
    setCurrentView(view);
  };

  const fetchData = async () => {
    setIsLoading(true);
    setLoadError(null);
    try {
      const [contactsRes, transRes, cashRes] = await Promise.all([
        supabase.from('contacts').select('*'),
        supabase.from('transactions').select('*'),
        supabase.from('cash_transactions').select('*').order('date', { ascending: false })
      ]);

      if (contactsRes.error) throw contactsRes.error;
      if (transRes.error) throw transRes.error;

      if (contactsRes.data) {
          const mappedContacts: Contact[] = contactsRes.data.map((c: any) => ({
              id: c.id,
              name: c.name,
              phone: c.phone || '',
              type: c.type,
              balance: c.balance || 0,
              targetAmount: c.target_amount,
              startDate: c.start_date,
              endDate: c.end_date,
              lastUpdated: c.last_updated
          }));
          setContacts(mappedContacts);
          contactsRef.current = mappedContacts; 
      }

      if (transRes.data) {
          const mappedTrans: Transaction[] = transRes.data.map((t: any) => ({
              id: t.id,
              contactId: t.contact_id,
              date: t.date,
              description: t.description,
              amount: t.amount,
              type: t.type,
              balanceAfter: t.balance_after,
              hasAttachment: t.has_attachment,
              attachmentUrl: t.attachment_url
          }));
          setTransactions(mappedTrans);
      }

      if (cashRes.data) {
        setCashTransactions(cashRes.data.map((c: any) => ({
          id: c.id,
          date: c.date,
          amount: c.amount,
          type: c.type,
          description: c.description
        })));
      }
    } catch (err: any) {
      console.error('Fetch error:', err);
      setLoadError(err.message || "Connection error. Check database settings.");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const currentTransactions = useMemo(() => {
    if (!selectedContact) return [];
    return transactions.filter(t => t.contactId === selectedContact.id).sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, selectedContact]);

  const filteredContacts = useMemo(() => {
      return contacts.filter(c => {
          const matchesType = c.type === activeTab;
          const query = searchQuery.toLowerCase().trim();
          const matchesSearch = !query || c.name.toLowerCase().includes(query) || c.phone.toLowerCase().includes(query);
          return matchesType && matchesSearch;
      });
  }, [contacts, activeTab, searchQuery]);

  const totals = useMemo(() => {
      const supplierTotal = contacts.filter(c => c.type === 'SUPPLIER').reduce((acc, c) => acc + (c.balance > 0 ? c.balance : 0), 0);
      const customerToCollect = contacts.filter(c => c.type === 'CUSTOMER').reduce((acc, c) => acc + (c.balance > 0 ? c.balance : 0), 0);
      const rentSaved = contacts.filter(c => c.type === 'RENT').reduce((acc, c) => acc + c.balance, 0);
      return { supplierTotal, customerToCollect, rentSaved };
  }, [contacts]);

  const cashSummary = useMemo(() => {
    const totalIn = cashTransactions.filter(t => t.type === 'IN').reduce((s, t) => s + t.amount, 0);
    const totalOut = cashTransactions.filter(t => t.type === 'OUT').reduce((s, t) => s + t.amount, 0);
    return { totalIn, totalOut, balance: totalIn - totalOut };
  }, [cashTransactions]);

  const handleNavigate = (view: string) => {
      if (view === currentView) return;
      navigateTo(view);
      if (view === 'DASHBOARD') setSelectedContact(null);
  };

  const handleBack = () => {
    window.history.back();
  };

  const openContact = (contact: Contact) => {
    setSelectedContact(contact);
    navigateTo('DETAIL', contact.id);
  };

  const handleAddContact = async () => {
    if (!addName.trim()) return;
    const newId = generateUUID();
    const payload = {
      id: newId,
      name: addName,
      phone: addPhone,
      type: activeTab,
      balance: 0,
      last_updated: new Date().toISOString()
    };
    try {
      const { data, error } = await supabase.from('contacts').insert([payload]).select();
      if (error) throw error;
      if (data) {
        const newContact: Contact = {
          id: data[0].id,
          name: data[0].name,
          phone: data[0].phone,
          type: data[0].type,
          balance: data[0].balance,
          lastUpdated: data[0].last_updated
        };
        setContacts([...contacts, newContact]);
        setAddName('');
        setAddPhone('');
        window.history.back();
      }
    } catch (err: any) {
      alert(err.message);
    }
  };

  const handleSaveTransaction = async () => {
      if (!selectedContact) return;
      const amountVal = parseFloat(transAmount) || 0;
      let newBalance = selectedContact.balance;
      if (selectedContact.type === 'RENT') {
          newBalance = transType === 'PAYMENT' ? newBalance + amountVal : newBalance - amountVal;
      } else {
          newBalance = transType === 'CREDIT' ? newBalance + amountVal : newBalance - amountVal;
      }

      const txPayload = {
          contact_id: selectedContact.id,
          date: transDate,
          amount: amountVal,
          type: transType,
          description: transDesc,
          balance_after: newBalance
      };

      try {
        const { data, error } = await supabase.from('transactions').insert([txPayload]).select();
        if (error) throw error;

        await supabase.from('contacts').update({ balance: newBalance, last_updated: new Date().toISOString() }).eq('id', selectedContact.id);

        if (data) {
          const savedTx = { id: data[0].id, contactId: data[0].contact_id, date: data[0].date, description: data[0].description, amount: data[0].amount, type: data[0].type, balanceAfter: data[0].balance_after };
          setTransactions([savedTx, ...transactions]);
        }

        const updatedContact = { ...selectedContact, balance: newBalance, lastUpdated: new Date().toISOString() };
        setContacts(contacts.map(c => c.id === selectedContact.id ? updatedContact : c));
        setSelectedContact(updatedContact);
        window.history.back();
      } catch (err: any) {
        alert(err.message);
      }
  };

  const handleSaveCashTransaction = async () => {
    const amount = parseFloat(cashAmount);
    if (isNaN(amount) || amount <= 0) return;
    const payload = {
      id: generateUUID(),
      date: new Date().toISOString(),
      amount: amount,
      type: cashType,
      description: cashDesc || (cashType === 'IN' ? 'Cash In' : 'Cash Out')
    };
    try {
      await supabase.from('cash_transactions').insert([payload]);
      setCashTransactions([payload, ...cashTransactions]);
      setCashAmount('');
      setCashDesc('');
      setIsCashFormOpen(false);
    } catch (e) {
      setCashTransactions([payload, ...cashTransactions]);
      setIsCashFormOpen(false);
    }
  };

  if (isLoading) {
    return (
        <div className="min-h-screen bg-gray-50 flex items-center justify-center flex-col gap-4">
            <Loader2 className="w-10 h-10 text-blue-600 animate-spin" />
            <p className="text-gray-400 font-medium animate-pulse">Syncing Ledger...</p>
        </div>
    );
  }

  if (loadError) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center p-6 text-center">
        <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100 max-w-sm">
          <AlertCircle size={48} className="text-red-500 mx-auto mb-4" />
          <h2 className="text-xl font-bold text-slate-800 mb-2">Sync Error</h2>
          <p className="text-gray-500 text-sm mb-6">{loadError}</p>
          <button onClick={fetchData} className="w-full bg-slate-800 text-white font-bold py-3 rounded-xl flex items-center justify-center gap-2">
            <RefreshCw size={18} /> Retry
          </button>
        </div>
      </div>
    );
  }

  if (currentView === 'DASHBOARD') {
      return (
        <div className="min-h-screen bg-gray-50 flex flex-col pb-20">
             <header className="bg-white px-4 py-3 pb-0 shadow-sm z-20 sticky top-0">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <h1 className="text-xl font-bold text-slate-800">Manage Credit</h1>
                    <div className="flex items-center text-slate-600 text-sm gap-1">
                      <span className="font-semibold">{shopName}</span>
                      <ChevronDown size={14} />
                    </div>
                  </div>
                  <div className="flex gap-4">
                    <button className="flex flex-col items-center gap-0.5 text-blue-600"><PlayCircle size={20} /><span className="text-[10px] font-medium">Demo</span></button>
                  </div>
                </div>
                <div className="flex gap-6 mt-4">
                   <button onClick={() => changeTab('CUSTOMER')} className={`flex items-center gap-2 pb-3 border-b-2 transition-colors font-medium ${activeTab === 'CUSTOMER' ? 'border-slate-800 text-slate-800' : 'border-transparent text-gray-500'}`}><Users size={18} />Customers</button>
                   <button onClick={() => changeTab('SUPPLIER')} className={`flex items-center gap-2 pb-3 border-b-2 transition-colors font-medium ${activeTab === 'SUPPLIER' ? 'border-slate-800 text-slate-800' : 'border-transparent text-gray-500'}`}><Truck size={18} />Suppliers</button>
                   <button onClick={() => changeTab('RENT')} className={`flex items-center gap-2 pb-3 border-b-2 transition-colors font-medium ${activeTab === 'RENT' ? 'border-slate-800 text-slate-800' : 'border-transparent text-gray-500'}`}><Building size={18} />Rent</button>
                </div>
            </header>
            <div className="p-4 flex flex-col gap-4">
                <div className="bg-white border border-gray-100 rounded-xl p-3 shadow-sm">
                    <p className="text-[10px] text-gray-400 font-bold uppercase mb-1">Total {activeTab === 'CUSTOMER' ? 'to collect' : 'to pay'}</p>
                    <p className={`text-lg font-bold ${activeTab === 'RENT' ? 'text-blue-600' : 'text-red-600'}`}>Rs. {(activeTab === 'CUSTOMER' ? totals.customerToCollect : activeTab === 'SUPPLIER' ? totals.supplierTotal : totals.rentSaved).toLocaleString()}</p>
                </div>
                <div className="bg-gray-100 rounded-lg px-3 py-2.5 flex items-center"><Search size={18} className="text-gray-400 mr-2" /><input type="text" placeholder="Search name or number" className="bg-transparent outline-none text-sm w-full" value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)} /></div>
                <div className="flex flex-col gap-2">
                    {filteredContacts.map(contact => (
                        <div key={contact.id} onClick={() => openContact(contact)} className="bg-white p-4 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between active:bg-gray-50 cursor-pointer">
                            <div className="flex items-center gap-3">
                                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-white ${contact.type === 'RENT' ? 'bg-blue-500' : 'bg-slate-400'}`}>{contact.name.substring(0, 1)}</div>
                                <div><h3 className="font-semibold text-slate-800">{contact.name}</h3><p className="text-xs text-gray-400">{contact.phone || 'No number'}</p></div>
                            </div>
                            <div className="text-right"><p className="text-[10px] text-gray-400 uppercase font-bold">Balance</p><p className={`font-bold ${contact.balance > 0 ? 'text-red-600' : 'text-green-600'}`}>{contact.balance.toLocaleString()}</p></div>
                        </div>
                    ))}
                    {filteredContacts.length === 0 && <div className="p-10 text-center text-gray-400">No contacts found</div>}
                </div>
            </div>
            <button onClick={() => navigateTo('ADD_CONTACT')} className={`fixed bottom-20 right-4 w-14 h-14 ${theme.primary} text-white rounded-full shadow-xl flex items-center justify-center z-30`}><Plus size={24} /></button>
            <BottomNav currentView={currentView} onNavigate={handleNavigate} activeTheme={appTheme} />
        </div>
      );
  }

  if (currentView === 'ADD_CONTACT') {
    return (
      <div className="min-h-screen bg-white flex flex-col">
        <header className="px-4 py-4 flex items-center gap-4 border-b border-gray-100">
          <button onClick={handleBack}><ChevronLeft size={24} className="text-slate-800" /></button>
          <h1 className="text-lg font-bold">Add {activeTab}</h1>
        </header>
        <div className="p-6 flex flex-col gap-6">
          <div><label className="text-xs font-bold text-gray-400 uppercase mb-2 block">Name</label><input value={addName} onChange={e => setAddName(e.target.value)} placeholder="Full name" className="w-full border-b-2 border-gray-100 py-3 text-lg font-semibold outline-none focus:border-blue-500 transition-colors" /></div>
          <div><label className="text-xs font-bold text-gray-400 uppercase mb-2 block">Phone (Optional)</label><input value={addPhone} onChange={e => setAddPhone(e.target.value)} placeholder="077..." className="w-full border-b-2 border-gray-100 py-3 text-lg font-semibold outline-none focus:border-blue-500 transition-colors" /></div>
          <button onClick={handleAddContact} className="w-full bg-slate-800 text-white font-bold py-4 rounded-xl shadow-lg mt-10">Add Contact</button>
        </div>
      </div>
    );
  }

  if (currentView === 'CASH_BOOK') {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col pb-20">
        <header className="bg-white px-4 py-4 shadow-sm sticky top-0">
          <h1 className="text-xl font-bold text-slate-800">Cash Book</h1>
        </header>
        <div className="p-4 flex flex-col gap-4">
          <div className="bg-slate-800 text-white rounded-2xl p-6">
            <p className="text-xs font-bold text-slate-400 uppercase">Balance</p>
            <h2 className="text-3xl font-bold">Rs. {cashSummary.balance.toLocaleString()}</h2>
          </div>
          <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            {cashTransactions.map((t) => (
              <div key={t.id} className="p-4 border-b border-gray-50 flex justify-between items-center">
                <div className="flex gap-3">
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${t.type === 'IN' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>{t.type === 'IN' ? <TrendingUp size={20} /> : <TrendingDown size={20} />}</div>
                  <div><p className="text-sm font-bold text-slate-800">{t.description}</p><p className="text-[10px] text-gray-400">{new Date(t.date).toLocaleDateString()}</p></div>
                </div>
                <p className={`font-bold ${t.type === 'IN' ? 'text-green-600' : 'text-red-600'}`}>{t.type === 'IN' ? '+' : '-'} {t.amount.toLocaleString()}</p>
              </div>
            ))}
            {cashTransactions.length === 0 && <div className="p-10 text-center text-gray-400">No cash entries</div>}
          </div>
        </div>
        {isCashFormOpen && (
          <div className="fixed inset-0 bg-black/50 z-50 flex items-end">
            <div className="bg-white w-full rounded-t-3xl p-6">
              <div className="flex gap-2 mb-6">
                <button onClick={() => setCashType('IN')} className={`flex-1 py-3 rounded-xl border-2 font-bold ${cashType === 'IN' ? 'border-green-600 text-green-700' : 'border-transparent bg-gray-50 text-gray-400'}`}>IN</button>
                <button onClick={() => setCashType('OUT')} className={`flex-1 py-3 rounded-xl border-2 font-bold ${cashType === 'OUT' ? 'border-red-600 text-red-700' : 'border-transparent bg-gray-50 text-gray-400'}`}>OUT</button>
              </div>
              <input type="number" value={cashAmount} onChange={e => setCashAmount(e.target.value)} placeholder="0.00" className="w-full text-2xl font-bold mb-4 py-2 border-b-2 border-gray-100 outline-none" />
              <input type="text" value={cashDesc} onChange={e => setCashDesc(e.target.value)} placeholder="Description" className="w-full text-lg mb-8 py-2 border-b-2 border-gray-100 outline-none" />
              <button onClick={handleSaveCashTransaction} className={`w-full ${cashType === 'IN' ? 'bg-green-600' : 'bg-red-600'} text-white font-bold py-4 rounded-xl`}>Save</button>
              <button onClick={() => setIsCashFormOpen(false)} className="w-full text-gray-400 mt-4 font-bold">Cancel</button>
            </div>
          </div>
        )}
        <button onClick={() => setIsCashFormOpen(true)} className="fixed bottom-20 right-4 w-14 h-14 bg-slate-800 text-white rounded-full flex items-center justify-center shadow-lg"><Plus size={24} /></button>
        <BottomNav currentView={currentView} onNavigate={handleNavigate} activeTheme={appTheme} />
      </div>
    );
  }

  if (currentView === 'PROFILE') {
      return (
        <div className="min-h-screen bg-gray-50 flex flex-col pb-20">
            <header className="bg-white px-4 py-4 shadow-sm"><h1 className="text-xl font-bold text-slate-800">Profile</h1></header>
            <div className="p-4"><div className="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><label className="text-xs text-gray-400 block mb-2 uppercase font-bold">Shop Name</label><input value={shopName} onChange={e => setShopName(e.target.value)} className="w-full text-lg font-bold border-b border-gray-100 outline-none" /></div></div>
            <BottomNav currentView={currentView} onNavigate={handleNavigate} activeTheme={appTheme} />
        </div>
      );
  }

  if (currentView === 'DETAIL' && selectedContact) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col pb-24 relative">
        <header className="bg-white sticky top-0 z-30 shadow-sm px-4 py-3 flex flex-col gap-3">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <button onClick={handleBack} className="p-1"><ChevronLeft size={24} className="text-slate-800" /></button>
              <div><h1 className="font-bold text-lg text-slate-800">{selectedContact.name}</h1><p className="text-xs text-gray-400">{selectedContact.phone}</p></div>
            </div>
          </div>
        </header>
        <div className="p-4 bg-white mb-2 shadow-sm"><div className="bg-gray-50 rounded-xl p-6 text-center border border-gray-100"><h2 className={`text-2xl font-bold ${selectedContact.balance > 0 ? 'text-red-600' : 'text-green-600'}`}>Rs. {Math.abs(selectedContact.balance).toLocaleString()}</h2><p className="text-gray-400 text-xs font-bold uppercase mt-1">{selectedContact.balance >= 0 ? (selectedContact.type === 'SUPPLIER' ? 'To Pay' : 'To Collect') : 'Settled'}</p></div></div>
        <div className="flex-1">
          {currentTransactions.length > 0 ? currentTransactions.map(t => <TransactionRow key={t.id} transaction={t} />) : <div className="p-10 text-center text-gray-400">No transactions yet</div>}
        </div>
        <div className="fixed bottom-0 left-0 right-0 bg-white px-4 pt-4 pb-10 flex gap-4 border-t border-gray-200 z-40">
          <button onClick={() => { setTransType('CREDIT'); setTransAmount(''); navigateTo('TRANSACTION_FORM', selectedContact.id); }} className="flex-1 bg-red-700 text-white font-bold py-3.5 rounded-xl flex items-center justify-center gap-2"><ArrowDown size={18} /> GAVE</button>
          <button onClick={() => { setTransType('PAYMENT'); setTransAmount(''); navigateTo('TRANSACTION_FORM', selectedContact.id); }} className="flex-1 bg-green-700 text-white font-bold py-3.5 rounded-xl flex items-center justify-center gap-2"><ArrowUp size={18} /> RECEIVED</button>
        </div>
      </div>
    );
  }

  if (currentView === 'TRANSACTION_FORM' && selectedContact) {
    return (
      <div className="min-h-screen bg-white flex flex-col">
        <header className="px-4 py-4 border-b border-gray-100 flex items-center gap-4"><button onClick={handleBack}><ChevronLeft size={24} className="text-slate-800" /></button><h1 className="text-lg font-bold">{transType === 'CREDIT' ? 'Gave' : 'Received'}</h1></header>
        <div className="p-6 flex-1">
          <label className="text-xs font-bold text-gray-400 mb-2 block uppercase">Amount</label>
          <input type="number" value={transAmount} onChange={e => setTransAmount(e.target.value)} placeholder="0.00" className={`w-full text-4xl font-bold mb-8 outline-none ${transType === 'CREDIT' ? 'text-red-600' : 'text-green-600'}`} autoFocus />
          <label className="text-xs font-bold text-gray-400 mb-2 block uppercase">Notes</label>
          <textarea value={transDesc} onChange={e => setTransDesc(e.target.value)} placeholder="Details..." className="w-full bg-gray-50 border border-gray-100 rounded-xl p-4 h-32 outline-none" />
        </div>
        <div className="p-6 pb-10"><button onClick={handleSaveTransaction} className={`w-full py-4 rounded-xl text-white font-bold shadow-lg ${transType === 'CREDIT' ? 'bg-red-700' : 'bg-green-700'}`}>Save Transaction</button></div>
      </div>
    );
  }

  return <div className="min-h-screen bg-gray-50 flex items-center justify-center">Error: View not found</div>;
}

