  if (currentView === 'DETAIL' && selectedContact) {
    const isRent = selectedContact.type === 'RENT';
    const labelLeft = isRent ? "WITHDRAW" : (selectedContact.type === 'SUPPLIER' ? "GOT ITEMS" : "GAVE ITEMS");
