  }

  if (currentView === 'PROFILE') {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col pb-20 no-scrollbar">
        <header className="bg-white px-6 py-8 shadow-sm flex flex-col items-center gap-4">
